func (s *Server) HandleIngest(w http.ResponseWriter, r *http.Request) {
    // Validate payload
    if err := s.validator.Validate(r.Body); err != nil {
        http.Error(w, "Invalid Schema", 400)
        return
    }
    // Push to Kafka
    s.kafkaProducer.Produce("raw-events", r.Body)
}
